#!/usr/bin/env node
'use strict';

/**
 * create-jira-ticket.js
 *
 * Creates a Jira issue from a Markdown ticket generated by the ticket-writer agent.
 *
 * Usage:
 *   node scripts/create-jira-ticket.js [options]
 *   cat ticket.md | node scripts/create-jira-ticket.js
 *
 * Options:
 *   --file <path>     Read ticket from a Markdown file (default: reads from stdin)
 *   --project <key>   Jira project key (overrides JIRA_PROJECT_KEY env var)
 *   --type <type>     Issue type: Story | Bug | Task | Spike (auto-detected if omitted)
 *   --dry-run         Validate and preview the payload without creating the issue
 *   --help            Show this help message
 *
 * Configuration (set in a .env file or as environment variables):
 *   JIRA_BASE_URL     Your Jira instance URL, e.g. https://yourorg.atlassian.net
 *   JIRA_EMAIL        Your Jira account email address
 *   JIRA_API_TOKEN    Your Jira API token (from id.atlassian.com/manage-profile/security/api-tokens)
 *   JIRA_PROJECT_KEY  Default project key (can be overridden with --project)
 *
 * Requires Node.js 18 or later.
 */

const fs = require('fs');
const path = require('path');

// ── Environment loading ──────────────────────────────────────────────────────

/**
 * Parses a .env file and returns its key-value pairs.
 * Lines starting with # and blank lines are ignored.
 * Values may be wrapped in single or double quotes.
 */
function loadEnvFile(filePath) {
  if (!fs.existsSync(filePath)) return {};
  const lines = fs.readFileSync(filePath, 'utf8').split('\n');
  const env = {};
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const eqIdx = trimmed.indexOf('=');
    if (eqIdx < 0) continue;
    const key = trimmed.slice(0, eqIdx).trim();
    let value = trimmed.slice(eqIdx + 1).trim();
    if (
      (value.startsWith('"') && value.endsWith('"')) ||
      (value.startsWith("'") && value.endsWith("'"))
    ) {
      value = value.slice(1, -1);
    }
    env[key] = value;
  }
  return env;
}

// ── CLI argument parsing ─────────────────────────────────────────────────────

function parseArgs(argv) {
  const args = argv.slice(2);
  const opts = { file: null, project: null, type: null, dryRun: false };

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--file':
        opts.file = args[++i];
        break;
      case '--project':
        opts.project = args[++i];
        break;
      case '--type':
        opts.type = args[++i];
        break;
      case '--dry-run':
        opts.dryRun = true;
        break;
      case '--help':
      case '-h':
        printUsage();
        process.exit(0);
        break;
      default:
        if (args[i].startsWith('--')) {
          console.error(`Unknown option: ${args[i]}`);
          printUsage();
          process.exit(1);
        }
    }
  }
  return opts;
}

function printUsage() {
  console.log(`
Usage: node scripts/create-jira-ticket.js [options]

Options:
  --file <path>     Read ticket from a Markdown file (default: reads from stdin)
  --project <key>   Jira project key (overrides JIRA_PROJECT_KEY env var)
  --type <type>     Issue type: Story | Bug | Task | Spike (auto-detected if omitted)
  --dry-run         Validate and preview the payload without creating the issue
  --help            Show this help message

Environment variables (set in a .env file or in your shell):
  JIRA_BASE_URL     Jira instance URL (e.g. https://yourorg.atlassian.net)
  JIRA_EMAIL        Your Jira account email address
  JIRA_API_TOKEN    Your Jira API token
  JIRA_PROJECT_KEY  Default Jira project key

Examples:
  node scripts/create-jira-ticket.js --file ticket.md
  node scripts/create-jira-ticket.js --file ticket.md --project ACME --type Story
  cat ticket.md | node scripts/create-jira-ticket.js --project ACME
  node scripts/create-jira-ticket.js --file ticket.md --dry-run
`.trim());
}

// ── Markdown parsing ─────────────────────────────────────────────────────────

/**
 * Extracts the ticket summary from Markdown.
 *
 * Priority order:
 * 1. The line immediately after a "## Summary" or "## Summary / Title" heading
 * 2. The first H1 or H2 heading in the document
 */
function extractSummary(markdown) {
  const lines = markdown.split('\n');

  for (let i = 0; i < lines.length; i++) {
    if (/^##\s+Summary(\s*\/\s*Title)?\s*$/i.test(lines[i].trim())) {
      // Find the first non-empty, non-comment line after this heading
      for (let j = i + 1; j < lines.length; j++) {
        const candidate = lines[j].trim();
        if (candidate && !candidate.startsWith('#') && !candidate.startsWith('<!--')) {
          return candidate;
        }
      }
    }
  }

  // Fall back to the first H1 or H2
  const headingMatch = markdown.match(/^#{1,2}\s+(.+)/m);
  if (headingMatch) return headingMatch[1].trim();

  return null;
}

/**
 * Detects the Jira issue type from the Markdown content.
 *
 * Detection strategy (in order):
 * 1. Explicit prefixes in the summary line (e.g. "Bug: …", "Task: …")
 * 2. Structural signals (section headings unique to each ticket type)
 * 3. Defaults to "Story"
 */
function detectIssueType(markdown) {
  // Check for explicit type prefixes in the summary content
  const summaryLineMatch = markdown.match(
    /^##\s+Summary(?:\s*\/\s*Title)?\s*\n+([^\n#]+)/im
  );
  if (summaryLineMatch) {
    const lower = summaryLineMatch[1].toLowerCase();
    if (/^bug[:\s]/.test(lower) || /\[bug\]/.test(lower)) return 'Bug';
    if (/^task[:\s]/.test(lower) || /\[task\]/.test(lower)) return 'Task';
    if (/^spike[:\s]/.test(lower) || /\[spike\]/.test(lower)) return 'Spike';
  }

  // Infer from section headings that are unique to each ticket type
  const lower = markdown.toLowerCase();
  if (
    lower.includes('## steps to replicate') ||
    lower.includes('## actual results') ||
    lower.includes('## desired outcome')
  ) {
    return 'Bug';
  }
  if (lower.includes('## goals') && lower.includes('## success criteria')) {
    return 'Spike';
  }
  if (!lower.includes('## user story') && lower.includes('## tech considerations')) {
    return 'Task';
  }

  return 'Story';
}

// ── Input reading ────────────────────────────────────────────────────────────

function readStdin() {
  return new Promise((resolve, reject) => {
    let data = '';
    process.stdin.setEncoding('utf8');
    process.stdin.on('data', (chunk) => {
      data += chunk;
    });
    process.stdin.on('end', () => resolve(data));
    process.stdin.on('error', reject);
  });
}

// ── Jira API ─────────────────────────────────────────────────────────────────

/**
 * Creates a Jira issue via the REST API v2.
 *
 * @param {object} opts
 * @param {string} opts.baseUrl       Jira instance base URL
 * @param {string} opts.email         Jira account email
 * @param {string} opts.token         Jira API token
 * @param {string} opts.projectKey    Jira project key
 * @param {string} opts.summary       Issue summary / title
 * @param {string} opts.description   Full Markdown description
 * @param {string} opts.issueType     Issue type name (Story, Bug, Task, Spike)
 * @returns {Promise<{key: string, id: string}>}
 */
async function createJiraIssue({ baseUrl, email, token, projectKey, summary, description, issueType }) {
  const apiUrl = `${baseUrl.replace(/\/$/, '')}/rest/api/2/issue`;
  const auth = Buffer.from(`${email}:${token}`).toString('base64');

  const payload = {
    fields: {
      project: { key: projectKey },
      summary,
      description,
      issuetype: { name: issueType },
    },
  };

  const response = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      Authorization: `Basic ${auth}`,
      'Content-Type': 'application/json',
      Accept: 'application/json',
    },
    body: JSON.stringify(payload),
  });

  const data = await response.json();

  if (!response.ok) {
    const errorMessages = data.errorMessages?.length
      ? data.errorMessages.join(', ')
      : null;
    const fieldErrors = data.errors
      ? Object.entries(data.errors)
          .map(([field, msg]) => `${field}: ${msg}`)
          .join(', ')
      : null;
    const message = errorMessages || fieldErrors || `HTTP ${response.status}`;
    throw new Error(`Jira API error (${response.status}): ${message}`);
  }

  return data;
}

// ── Main ─────────────────────────────────────────────────────────────────────

async function main() {
  const opts = parseArgs(process.argv);

  // Load environment: .env file is looked up from the current working directory
  // (project root when run from there) with a fallback to the script's directory.
  // Real environment variables always take precedence over .env file values.
  const envFileCwd = path.resolve(process.cwd(), '.env');
  const envFileScript = path.resolve(__dirname, '..', '.env');
  const envFilePath = fs.existsSync(envFileCwd) ? envFileCwd : envFileScript;
  const fileEnv = loadEnvFile(envFilePath);
  const env = { ...fileEnv, ...process.env };

  // Read Markdown content
  let markdown;
  if (opts.file) {
    const filePath = path.resolve(opts.file);
    if (!fs.existsSync(filePath)) {
      console.error(`Error: File not found: ${filePath}`);
      process.exit(1);
    }
    markdown = fs.readFileSync(filePath, 'utf8');
  } else if (!process.stdin.isTTY) {
    markdown = await readStdin();
  } else {
    console.error(
      'Error: No input provided. Use --file <path> to specify a Markdown file, or pipe content via stdin.'
    );
    console.error('Run with --help for usage information.');
    process.exit(1);
  }

  if (!markdown.trim()) {
    console.error('Error: The input Markdown is empty.');
    process.exit(1);
  }

  // Parse the Markdown
  const summary = extractSummary(markdown);
  if (!summary) {
    console.error(
      'Error: Could not extract a ticket summary from the Markdown.\n' +
        'Ensure the file has a "## Summary" section or a top-level heading.'
    );
    process.exit(1);
  }

  const issueType = opts.type || detectIssueType(markdown);
  const projectKey = opts.project || env.JIRA_PROJECT_KEY;

  // Validate required configuration
  const missing = [];
  if (!env.JIRA_BASE_URL) missing.push('JIRA_BASE_URL');
  if (!env.JIRA_EMAIL) missing.push('JIRA_EMAIL');
  if (!env.JIRA_API_TOKEN) missing.push('JIRA_API_TOKEN');
  if (!projectKey) missing.push('JIRA_PROJECT_KEY (or pass --project <key>)');

  if (missing.length > 0) {
    console.error(
      `Error: Missing required configuration:\n  ${missing.join('\n  ')}\n\n` +
        'Copy .env.example to .env and fill in your credentials.'
    );
    process.exit(1);
  }

  // Preview
  console.log('\nTicket preview:');
  console.log(`  Summary  : ${summary}`);
  console.log(`  Type     : ${issueType}`);
  console.log(`  Project  : ${projectKey}`);
  console.log(`  Jira URL : ${env.JIRA_BASE_URL}`);

  if (opts.dryRun) {
    console.log('\n[Dry run] Request validated. No issue was created.');
    return;
  }

  console.log('\nCreating Jira issue...');

  try {
    const result = await createJiraIssue({
      baseUrl: env.JIRA_BASE_URL,
      email: env.JIRA_EMAIL,
      token: env.JIRA_API_TOKEN,
      projectKey,
      summary,
      description: markdown,
      issueType,
    });

    const issueUrl = `${env.JIRA_BASE_URL.replace(/\/$/, '')}/browse/${result.key}`;
    console.log(`\nIssue created: ${result.key}`);
    console.log(`URL: ${issueUrl}`);
  } catch (err) {
    console.error(`\nFailed to create issue: ${err.message}`);
    process.exit(1);
  }
}

main().catch((err) => {
  console.error(`Unexpected error: ${err.message}`);
  process.exit(1);
});
